import pytest

from risky_module import divide, parse_expression, hide_error


class TestDivide:
    def test_divide_happy_path(self):
        assert divide(10, 2) == 5.0

    def test_divide_negative(self):
        assert divide(-6, 3) == -2.0

    def test_divide_float_result(self):
        assert divide(1, 4) == 0.25

    def test_divide_by_zero_raises(self):
        with pytest.raises(ZeroDivisionError):
            divide(1, 0)

    def test_divide_zero_numerator(self):
        assert divide(0, 5) == 0.0


class TestParseExpression:
    def test_parse_expression_callable_with_int(self):
        assert parse_expression("42") == 42

    def test_parse_expression_callable_with_list(self):
        assert parse_expression("[1, 2, 3]") == [1, 2, 3]

    def test_parse_expression_callable_with_dict(self):
        assert parse_expression("{'a': 1}") == {"a": 1}


class TestHideError:
    def test_hide_error_valid_int(self):
        assert hide_error("123") == 123

    def test_hide_error_invalid_string_returns_zero(self):
        assert hide_error("not-a-number") == 0

    def test_hide_error_empty_string_returns_zero(self):
        assert hide_error("") == 0

import pytest

import risky_module


def test_divide_happy_path():
    assert risky_module.divide(10, 2) == 5.0


def test_divide_negative_numbers():
    assert risky_module.divide(-9, 3) == -3.0


def test_divide_float_result():
    assert risky_module.divide(1, 4) == 0.25


def test_divide_by_zero_raises():
    with pytest.raises(ZeroDivisionError):
        risky_module.divide(1, 0)


def test_parse_expression_smoke_callable():
    result = risky_module.parse_expression("1 + 2")
    assert result == 3


def test_parse_expression_list_literal():
    result = risky_module.parse_expression("[1, 2, 3]")
    assert result == [1, 2, 3]


def test_hide_error_valid_integer():
    assert risky_module.hide_error("42") == 42


def test_hide_error_invalid_returns_zero():
    assert risky_module.hide_error("not-a-number") == 0


def test_hide_error_empty_string_returns_zero():
    assert risky_module.hide_error("") == 0
